import warnings
warnings.filterwarnings("ignore", category=DeprecationWarning)

import os
from fpdf import FPDF

OUTPUT_DIR = os.path.join(os.path.dirname(os.path.abspath(__file__)), "sample-contracts")
os.makedirs(OUTPUT_DIR, exist_ok=True)


class ContractPDF(FPDF):
    def __init__(self, title="", *args, **kwargs):
        super().__init__(*args, **kwargs)
        self._doc_title = title
        self.set_auto_page_break(auto=True, margin=25)

    def header(self):
        if self.page_no() > 1:
            self.set_font("Helvetica", "I", 8)
            self.cell(0, 5, self._doc_title, align="C", ln=True)
            self.set_draw_color(180, 180, 180)
            self.line(10, self.get_y(), 200, self.get_y())
            self.ln(4)

    def footer(self):
        self.set_y(-20)
        self.set_font("Helvetica", "I", 8)
        self.cell(0, 10, f"Page {self.page_no()}/{{{chr(110)}b}}", align="C", ln=True)
        self.cell(0, 4, "CONFIDENTIAL", align="C", ln=True)

    def title_page(self, doc_type, parties, date_line, reference=""):
        self.add_page()
        self.ln(50)
        self.set_font("Helvetica", "B", 26)
        self.cell(0, 14, doc_type, align="C", ln=True)
        self.ln(8)
        self.set_draw_color(0, 51, 102)
        self.set_line_width(0.8)
        self.line(60, self.get_y(), 150, self.get_y())
        self.ln(12)
        self.set_font("Helvetica", "", 14)
        for p in parties:
            self.cell(0, 10, p, align="C", ln=True)
        self.ln(10)
        self.set_font("Helvetica", "I", 12)
        self.cell(0, 8, date_line, align="C", ln=True)
        if reference:
            self.ln(4)
            self.set_font("Helvetica", "", 11)
            self.cell(0, 8, reference, align="C", ln=True)

    def section_heading(self, number, title):
        self.ln(4)
        self.set_font("Helvetica", "B", 12)
        self.cell(0, 8, f"{number}. {title}", ln=True)
        self.ln(1)

    def subsection_heading(self, number, title):
        self.set_font("Helvetica", "B", 10)
        self.cell(0, 7, f"    {number} {title}", ln=True)

    def body_text(self, text):
        self.set_font("Helvetica", "", 10)
        self.multi_cell(0, 5.5, text, ln=True)
        self.ln(1)

    def signature_block(self, parties):
        self.ln(8)
        self.set_font("Helvetica", "B", 11)
        self.cell(0, 7, "IN WITNESS WHEREOF, the Parties have executed this Agreement as of the date first written above.", ln=True)
        self.ln(10)
        col_w = 90
        y_start = self.get_y()
        for i, (name, title, company) in enumerate(parties):
            x = 10 + i * col_w
            self.set_xy(x, y_start)
            self.set_font("Helvetica", "B", 10)
            self.cell(col_w, 6, company, ln=True)
            self.set_x(x)
            self.ln(12)
            self.set_x(x)
            self.set_draw_color(0, 0, 0)
            self.line(x, self.get_y(), x + 75, self.get_y())
            self.ln(2)
            self.set_font("Helvetica", "", 9)
            self.set_x(x)
            self.cell(col_w, 5, f"Name: {name}", ln=True)
            self.set_x(x)
            self.cell(col_w, 5, f"Title: {title}", ln=True)
            self.set_x(x)
            self.cell(col_w, 5, "Date: _______________", ln=True)


def gen_nda():
    pdf = ContractPDF("Mutual Non-Disclosure Agreement - TechCorp / Nexus Dynamics")
    pdf.alias_nb_pages()
    pdf.title_page("MUTUAL NON-DISCLOSURE AGREEMENT", ["TechCorp Solutions, Inc.", "and", "Nexus Dynamics LLC"], "Effective Date: January 15, 2024")
    pdf.add_page()
    pdf.body_text('This Mutual Non-Disclosure Agreement ("Agreement") is entered into as of January 15, 2024 (the "Effective Date") by and between TechCorp Solutions, Inc., a Delaware corporation with its principal office at 1200 Innovation Drive, San Jose, CA 95134 ("TechCorp"), and Nexus Dynamics LLC, a California limited liability company with its principal office at 800 Market Street, Suite 400, San Francisco, CA 94102 ("Nexus Dynamics"). TechCorp and Nexus Dynamics are each referred to herein as a "Party" and collectively as the "Parties."')
    pdf.section_heading("1", "PURPOSE")
    pdf.body_text('The Parties wish to explore a potential business relationship concerning joint technology development and strategic partnership opportunities (the "Purpose"). In connection with the Purpose, each Party may disclose to the other certain confidential and proprietary information. The Parties desire to establish the terms under which such information will be disclosed and protected.')
    pdf.section_heading("2", "DEFINITION OF CONFIDENTIAL INFORMATION")
    pdf.body_text('"Confidential Information" means any and all non-public, proprietary, or confidential information disclosed by either Party (the "Disclosing Party") to the other Party (the "Receiving Party"), whether orally, in writing, electronically, or by inspection of tangible objects, including but not limited to: (a) trade secrets, inventions, ideas, processes, formulas, source and object code, data, programs, software, other works of authorship, know-how, improvements, discoveries, and developments; (b) information regarding plans for research, development, new products, marketing and selling, business plans, budgets and unpublished financial statements, licenses, prices and costs, margins, discounts, credit terms, pricing and billing policies, quoting procedures, methods of obtaining business, forecasts, future plans, and potential strategies; (c) information regarding customers, suppliers, joint venture partners, and potential customers; and (d) information regarding the skills and compensation of employees, contractors, or agents of the Disclosing Party.')
    pdf.section_heading("3", "OBLIGATIONS OF THE RECEIVING PARTY")
    pdf.subsection_heading("3.1", "Non-Disclosure")
    pdf.body_text("The Receiving Party shall not disclose any Confidential Information of the Disclosing Party to any third party without the prior written consent of the Disclosing Party, except to those employees, officers, directors, agents, consultants, and advisors of the Receiving Party who have a need to know such information for the Purpose and who are bound by obligations of confidentiality at least as protective as those contained herein.")
    pdf.subsection_heading("3.2", "Standard of Care")
    pdf.body_text("The Receiving Party shall protect the Disclosing Party's Confidential Information using the same degree of care that the Receiving Party uses to protect its own confidential information of a similar nature, but in no event less than reasonable care. The Receiving Party shall promptly notify the Disclosing Party in writing of any misuse, misappropriation, or unauthorized disclosure of Confidential Information of which the Receiving Party becomes aware.")
    pdf.subsection_heading("3.3", "Restricted Use")
    pdf.body_text("The Receiving Party shall use the Confidential Information solely for the Purpose and shall not use or exploit the Confidential Information for its own benefit or the benefit of any third party without the prior written consent of the Disclosing Party.")
    pdf.section_heading("4", "EXCLUSIONS FROM CONFIDENTIAL INFORMATION")
    pdf.body_text("Confidential Information shall not include information that: (a) is or becomes publicly available through no fault of the Receiving Party; (b) was known to the Receiving Party prior to disclosure by the Disclosing Party, as evidenced by written records; (c) is rightfully received by the Receiving Party from a third party without restriction on disclosure; or (d) is independently developed by the Receiving Party without use of or reference to the Disclosing Party's Confidential Information, as demonstrated by documented evidence.")
    pdf.section_heading("5", "TERM AND TERMINATION")
    pdf.body_text('This Agreement shall commence on the Effective Date and shall remain in effect for a period of three (3) years (the "Term"), unless earlier terminated by either Party upon thirty (30) days\' prior written notice to the other Party. The obligations of confidentiality set forth herein shall survive the expiration or termination of this Agreement for a period of three (3) years from the date of disclosure of the applicable Confidential Information.')
    pdf.section_heading("6", "RETURN OR DESTRUCTION OF MATERIALS")
    pdf.body_text("Upon termination or expiration of this Agreement, or upon the Disclosing Party's written request, the Receiving Party shall promptly return or destroy all tangible materials embodying Confidential Information, including all copies, notes, summaries, and extracts thereof. The Receiving Party shall certify in writing the completion of such return or destruction within fifteen (15) business days.")
    pdf.section_heading("7", "REMEDIES")
    pdf.body_text("Each Party acknowledges that any breach of this Agreement may cause irreparable harm to the Disclosing Party for which monetary damages may be inadequate. Accordingly, the Disclosing Party shall be entitled to seek equitable relief, including injunctive relief and specific performance, in addition to all other remedies available at law or in equity, without the need to post a bond.")
    pdf.section_heading("8", "GOVERNING LAW AND DISPUTE RESOLUTION")
    pdf.body_text("This Agreement shall be governed by and construed in accordance with the laws of the State of California, without regard to its conflict of laws principles. Any dispute arising out of or in connection with this Agreement shall be resolved through binding arbitration administered by the American Arbitration Association in San Jose, California, in accordance with its Commercial Arbitration Rules.")
    pdf.section_heading("9", "GENERAL PROVISIONS")
    pdf.body_text("This Agreement constitutes the entire agreement between the Parties with respect to the subject matter hereof and supersedes all prior and contemporaneous agreements, understandings, negotiations, and discussions. This Agreement may be amended only by a written instrument signed by both Parties. Neither Party may assign this Agreement without the prior written consent of the other Party. If any provision of this Agreement is held to be invalid or unenforceable, the remaining provisions shall continue in full force and effect.")
    pdf.signature_block([("James R. Whitfield", "Chief Executive Officer", "TechCorp Solutions, Inc."), ("Sarah M. Chen", "Managing Director", "Nexus Dynamics LLC")])
    pdf.output(os.path.join(OUTPUT_DIR, "Mutual-NDA-TechCorp-Nexus-2024.pdf"))


