    pdf.subsection_heading("2.2", "Restrictions")
    pdf.body_text("Customer shall not: (a) sublicense, sell, resell, transfer, assign, distribute, or otherwise commercially exploit or make available to any third party the Services; (b) modify or make derivative works based upon the Services; (c) reverse engineer, disassemble, or decompile the Services or apply any other process to derive the source code; (d) access the Services in order to build a competitive product or service or copy any features, functions, or graphics of the Services.")
    pdf.section_heading("3", "FEES AND PAYMENT")
