def gen_sow():
    pdf = ContractPDF("SOW #001 - Data Migration Project - Pinnacle Consulting")
    pdf.alias_nb_pages()
    pdf.title_page("STATEMENT OF WORK #001", ["Apple Inc.", "and", "Pinnacle Consulting Group, Inc."], "Effective Date: August 1, 2023", "Reference: MSA Agreement No. AAPL-PCG-MSA-2023-070")
    pdf.add_page()
    pdf.body_text('This Statement of Work #001 ("SOW") is entered into as of August 1, 2023, pursuant to and governed by the Master Service Agreement dated July 1, 2023 (the "MSA") between Apple Inc. ("Client") and Pinnacle Consulting Group, Inc. ("Consultant"). In the event of any conflict between this SOW and the MSA, the terms of this SOW shall control with respect to the services described herein.')
    pdf.section_heading("1", "PROJECT OVERVIEW")
    pdf.body_text('The purpose of this SOW is to define the scope, timeline, deliverables, and commercial terms for the Enterprise Data Migration Project (the "Project"). The Project involves the migration of Client\'s legacy on-premises data infrastructure, comprising approximately 50 terabytes of structured and unstructured data across 12 business-critical systems, to Client\'s designated cloud platform environment.')
    pdf.section_heading("2", "SCOPE OF WORK")
    pdf.subsection_heading("2.1", "Phase 1 - Discovery and Assessment (Weeks 1-4)")
    pdf.body_text("Consultant shall: (a) conduct a comprehensive inventory and assessment of existing data sources, schemas, and dependencies; (b) perform data quality analysis and profiling across all source systems; (c) identify and document data transformation requirements; (d) develop a detailed migration plan including risk mitigation strategies; (e) deliver a Discovery Report and Migration Architecture Document for Client review and approval.")
    pdf.subsection_heading("2.2", "Phase 2 - Design and Development (Weeks 5-12)")
    pdf.body_text("Consultant shall: (a) design the target data architecture and data models; (b) develop ETL/ELT pipelines for data extraction, transformation, and loading; (c) implement data validation and reconciliation frameworks; (d) configure the target cloud environment in accordance with Client's security and compliance requirements; (e) develop comprehensive test plans and test scripts.")
    pdf.subsection_heading("2.3", "Phase 3 - Testing and Validation (Weeks 13-18)")
    pdf.body_text("Consultant shall: (a) execute unit, integration, and system testing of all migration components; (b) perform parallel run testing comparing source and target data; (c) conduct user acceptance testing (UAT) with Client stakeholders; (d) remediate all identified defects; (e) obtain Client sign-off on test results prior to production migration.")
    pdf.subsection_heading("2.4", "Phase 4 - Production Migration and Cutover (Weeks 19-22)")
    pdf.body_text("Consultant shall: (a) execute the production data migration during agreed-upon maintenance windows; (b) perform post-migration data validation and integrity checks; (c) support Client's go/no-go decision process; (d) execute cutover to the new environment; (e) decommission legacy data systems upon Client approval.")
    pdf.subsection_heading("2.5", "Phase 5 - Hypercare and Knowledge Transfer (Weeks 23-26)")
    pdf.body_text("Consultant shall: (a) provide dedicated on-site and remote support during the hypercare period; (b) monitor system performance and data integrity; (c) resolve any post-migration issues; (d) deliver comprehensive knowledge transfer sessions and documentation to Client's IT team; (e) provide a final Project Closure Report.")
    pdf.section_heading("3", "DELIVERABLES")
    pdf.body_text("The following deliverables shall be provided under this SOW:\n  - Discovery Report and Data Inventory\n  - Migration Architecture Document\n  - ETL/ELT Pipeline Source Code and Configuration\n  - Data Validation and Reconciliation Reports\n  - Test Plans, Test Scripts, and Test Results\n  - UAT Sign-Off Documentation\n  - Post-Migration Validation Report\n  - Knowledge Transfer Materials and Runbooks\n  - Project Closure Report")
    pdf.section_heading("4", "PROJECT TIMELINE")
    pdf.body_text("The Project shall be completed within twenty-six (26) weeks from the SOW Effective Date, with a target completion date of January 31, 2024. Key milestones are as follows:\n  - Discovery Complete: August 28, 2023\n  - Design & Development Complete: October 23, 2023\n  - Testing & Validation Complete: December 8, 2023\n  - Production Migration Complete: January 12, 2024\n  - Project Closure: January 31, 2024")
    pdf.section_heading("5", "FEES AND PAYMENT SCHEDULE")
    pdf.subsection_heading("5.1", "Total Project Fee")
    pdf.body_text("The total fixed price for the Project is One Million Two Hundred Thousand Dollars ($1,200,000.00) USD. This fee is inclusive of all labor, materials, and Consultant expenses associated with the performance of the services described in this SOW.")
    pdf.subsection_heading("5.2", "Payment Milestones")
    pdf.body_text("Payment shall be made according to the following milestone schedule:\n  - SOW Execution (Deposit): $180,000 (15%)\n  - Discovery Phase Complete: $180,000 (15%)\n  - Design & Development Complete: $300,000 (25%)\n  - Testing & Validation Complete: $240,000 (20%)\n  - Production Migration Complete: $180,000 (15%)\n  - Project Closure & Final Acceptance: $120,000 (10%)")
    pdf.section_heading("6", "PROJECT TEAM")
